#include <stdio.h>
#include <arpa/inet.h>
#include <netinet/in.h>
#include <string.h>

/* == EXEMPLE ===============================================
 * sockaddr_in : configurer une adresse IPv4 pour 192.168.0.1:443
 * htons convertit le port en big-endian, inet_pton l'IP en binaire.
 * ========================================================= */
void example_setup_addr(void) {
    struct sockaddr_in a;
    memset(&a, 0, sizeof(a));
    a.sin_family = AF_INET;
    a.sin_port = htons(443);
    inet_pton(AF_INET, "192.168.0.1", &a.sin_addr);
    char buf[INET_ADDRSTRLEN];
    inet_ntop(AF_INET, &a.sin_addr, buf, sizeof(buf));
    printf("example: %s:%d (family=%d)\n", buf, ntohs(a.sin_port), a.sin_family);
}
/* Resultat: example: 192.168.0.1:443 (family=2) */

